    55→interface ModalNovoAgendamentoProps {
    56→  isOpen: boolean;
    57→  onClose: () => void;
    58→  profissionalId?: string;
    59→  data: string;
    60→  horarioInicio: string;
    61→  initialClientId?: string;
    62→  onAppointmentCreated?: (appointment: { id: string; date: string; time: string; professionalId: string }) => void;
    63→}
    64→
    65→interface Cliente {
    66→  id: string;
    67→  nome: string;
    68→  telefone: string;
    69→}
    70→
    71→interface Servico {
    72→  id: string;
    73→  nome: string;
    74→  duracao: number;
    75→  preco: number;
    76→}
    77→
    78→interface ProfessionalServiceConfig {
    79→  customDuration?: number;
    80→  customPrice?: number;
    81→}
    82→
    83→interface Profissional {
    84→  id: string;
    85→  nome: string;
    86→  name: string;
    87→  nickname?: string;
    88→}
    89→
    90→// Helper para converter string yyyy-MM-dd em objeto Date local sem problemas de timezone
    91→const parseLocalDate = (dateStr: string): Date | null => {
    92→  if (!dateStr) return null;
    93→  const [year, month, day] = dateStr.split("-").map(Number);
    94→  if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
    95→  return new Date(year, month - 1, day);
    96→};
    97→
    98→export function ModalNovoAgendamento({
    99→  isOpen,
   100→  onClose,
   101→  profissionalId,
   102→  data,
   103→  horarioInicio,
   104→  initialClientId,
   105→  onAppointmentCreated,
   106→}: ModalNovoAgendamentoProps): JSX.Element {
   107→  const { selectedSalon } = useSelectedSalon();
   108→  const { user } = useAuth();
   109→  const isMobile = useIsMobile();
   110→  const [isLoading, setIsLoading] = useState(false);
   111→  const [isSaving, setIsSaving] = useState(false);
   112→
   113→  // Estados para dados da API
   114→  const [clientes, setClientes] = useState<Cliente[]>([]);
   115→  const [servicos, setServicos] = useState<Servico[]>([]);
   116→  const [servicosFiltrados, setServicosFiltrados] = useState<Servico[]>([]);
   117→  const [profissionais, setProfissionais] = useState<Profissional[]>([]);
   118→  const [profissionaisFiltrados, setProfissionaisFiltrados] = useState<Profissional[]>([]);
   119→  const [loadingProfissionais, setLoadingProfissionais] = useState(false);
   120→  const [loadingServicos, setLoadingServicos] = useState(false);
   121→  const [horariosDisponiveis, setHorariosDisponiveis] = useState<
   122→    { slot: string; available: boolean }[]
   123→  >([]);
   124→  const [salonOpeningHours, setSalonOpeningHours] = useState<any[]>([]);
   125→  const [loadingHorarios, setLoadingHorarios] = useState(false);
   126→  const [professionalServiceConfig, setProfessionalServiceConfig] =
   127→    useState<ProfessionalServiceConfig | null>(null);
   128→
   129→  // Estados do formulário
   130→  const [clienteSelecionado, setClienteSelecionado] = useState<string>(initialClientId || "");
   131→  const [servicoSelecionado, setServicoSelecionado] = useState<string>("");
   132→  const [profissionalSelecionado, setProfissionalSelecionado] =
   133→    useState<string>(profissionalId || "");
   134→  const [dataSelecionada, setDataSelecionada] = useState<string>(
   135→    data ? (typeof data === 'string' ? data : format(data, "yyyy-MM-dd")) : ""
   136→  );
   137→  const [horarioSelecionado, setHorarioSelecionado] = useState<string>(horarioInicio);
   138→  const [precoProfissional, setPrecoProfissional] = useState<number | null>(
   139→    null
   140→  );
   141→
   142→  // Estados dos popovers
   143→  const [openCliente, setOpenCliente] = useState(false);
   144→  const [openServico, setOpenServico] = useState(false);
   145→  const [openProfissional, setOpenProfissional] = useState(false);
   146→  const [openHorario, setOpenHorario] = useState(false);
   147→
   148→  // Estados para cadastro simplificado de cliente
   149→  const [isModoCadastroCliente, setIsModoCadastroCliente] = useState(false);
   150→  const [novoCliente, setNovoCliente] = useState({ nome: "", telefone: "" });
   151→  const [isCriandoCliente, setIsCriandoCliente] = useState(false);
   152→  
   153→  // Refs para controle de inicialização em cascata (Onboarding)
   154→  const serviceInitialized = useRef(false);
   155→  const profInitialized = useRef(false);
   156→  const slotInitialized = useRef(false);
   157→  // Função para obter mensagem de validação de data
   158→  const getDateValidationMessage = (): string | null => {
   159→    if (!dataSelecionada) return null;
   160→
   161→    const today = new Date();
   162→    today.setHours(0, 0, 0, 0);
   163→
   164→    const selectedDateObj = parseLocalDate(dataSelecionada);
   165→
   166→    if (!selectedDateObj || isNaN(selectedDateObj.getTime())) {
   167→      return "Data inválida";
   168→    }
   169→
   170→    if (selectedDateObj < today) {
   171→      return "Data não pode ser anterior a hoje";
   172→    }
   173→
   174→    return null;
   175→  };
   176→
   177→  // Track modal open
   178→  useEffect(() => {
   179→    if (!isOpen) return;
   180→    analytics.trackEvent("appointment_modal_opened", {
   181→      has_preselected_professional: !!profissionalId,
   182→      has_preselected_time: !!horarioInicio,
   183→    });
   184→  }, [isOpen]);
   185→
   186→  // Fetch data from API
   187→  useEffect(() => {
   188→    const fetchData = async (): Promise<void> => {
   189→      const salonId =
   190→        selectedSalon?.id || localStorage.getItem("selectedSalonId");
   191→
   192→      if (!isOpen || !salonId) {
   193→        return;
   194→      }
   195→
   196→      setIsLoading(true);
   197→      setIsModoCadastroCliente(false);
   198→      setNovoCliente({ nome: "", telefone: "" });
   199→
   200→      try {
   201→        // Sempre buscar dados frescos quando o modal abrir
   202→        const [
   203→          servicesResponse,
   204→          professionalsResponse,
   205→          clientsResponse,
   206→          salonHoursResponse,
   207→        ] = await Promise.all([
   208→          serviceService.getBookableServices(),
   209→          userService.list({
   210→            role: "professional" as any,
   211→            salonId,
   212→          }),
   213→          clientService.list({
   214→            limit: "100",
   215→            sortBy: "name",
   216→            sortOrder: "ASC",
   217→          }),
   218→          agendaService.getSalonOperatingHours(salonId),
   219→        ]);
   220→
   221→        // Inicializar servicosFiltrados com todos os serviços
   222→        const allServices = (servicesResponse || [])
   223→          .filter((s) => s?.duration && s?.duration > 0)
   224→          .map((s) => ({
   225→            id: s.id,
   226→            nome: s.name,
   227→            duracao: s.duration,
   228→            preco:
   229→              typeof s.price === "string" ? parseFloat(s.price) : s.price,
   230→          }));
   231→
   232→        setServicos(allServices);
   233→        setServicosFiltrados(allServices);
   234→
   235→        setProfissionais(
   236→          (professionalsResponse?.data || []).map((p) => ({
   237→            id: p.id,
   238→            nome: p.name,
   239→            name: p.name,
   240→            nickname: p.nickname,
   241→          }))
   242→        );
   243→
   244→        setClientes(
   245→          (clientsResponse?.data || []).map((c) => ({
   246→            id: c.id,
   247→            nome: c.name,
   248→            telefone: c.phone,
   249→          }))
   250→        );
   251→
   252→        // Processar horários do salão
   253→        if (salonHoursResponse && salonHoursResponse.openingHours) {
   254→          setSalonOpeningHours(salonHoursResponse.openingHours);
   255→        }
   256→      } catch (error) {
   257→        console.error("[ModalNovoAgendamento] Error fetching data:", error);
   258→        toast.error("Erro ao carregar dados");
   259→      } finally {
   260→        setIsLoading(false);
   261→      }
   262→    };
   263→
   264→    fetchData();
   265→  }, [isOpen, selectedSalon?.id, user?.id]);
   266→
   267→  // Filter services based on selected professional
   268→  useEffect(() => {
   269→    const filterServicesByProfessional = async () => {
   270→      // If no professional selected, show all services
   271→      if (!profissionalSelecionado) {
   272→        setServicosFiltrados(servicos);
   273→        return;
   274→      }
   275→
   276→      setLoadingServicos(true);
   277→      try {
   278→        // Fetch services for the selected professional
   279→        const userServices = await userService.getUserServices(
   280→          profissionalSelecionado
   281→        );
   282→
   283→        // Filter the full service list to only include those offered by the professional
   284→        const filteredServices = servicos.filter((service) => {
   285→          // Check if professional has this service associated and active
   286→          const userService = userServices.find(
   287→            (us: any) => {
   288→              const matchesService =
   289→                us.serviceId === service.id ||
   290→                us.id === service.id ||
   291→                us.service_id === service.id;
   292→
   293→              const isActive = us.isActive !== false && us.is_active !== false;
   294→
   295→              return matchesService && isActive;
   296→            }
   297→          );
   298→          return !!userService;
   299→        });
   300→
   301→        // Set the filtered list
   302→        setServicosFiltrados(filteredServices);
   303→
   304→        // If a service was already selected but is not offered by this professional, clear selection
   305→        if (
   306→          servicoSelecionado &&
   307→          !filteredServices.some((s) => s.id === servicoSelecionado)
   308→        ) {
   309→          setServicoSelecionado("");
   310→          toast.info(
   311→            "Serviço desmarcado pois não é oferecido pelo profissional selecionado"
   312→          );
   313→        }
   314→      } catch (error) {
   315→        console.error("Error filtering services by professional:", error);
   316→        // On error, fallback to showing all services to avoid blocking the user
   317→        setServicosFiltrados(servicos);
   318→      } finally {
   319→        setLoadingServicos(false);
   320→      }
   321→    };
   322→
   323→    if (isOpen) {
   324→      filterServicesByProfessional();
   325→    }
   326→  }, [profissionalSelecionado, servicos, isOpen]);
   327→
   328→  // Auto-seleção de cliente único
   329→  useEffect(() => {
   330→    if (!isOpen || clienteSelecionado || clientes.length !== 1) return;
   331→    setClienteSelecionado(clientes[0].id);
   332→  }, [clientes, isOpen, clienteSelecionado]);
   333→
   334→  // Waterfall Fase 1: Serviço (Auto-seleção se houver apenas uma opção)
   335→  useEffect(() => {
   336→    if (serviceInitialized.current || !isOpen || servicosFiltrados.length !== 1) return;
   337→    
   338→    setServicoSelecionado(servicosFiltrados[0].id);
   339→    serviceInitialized.current = true;
   340→  }, [servicosFiltrados, isOpen]);
   341→
   342→  // Waterfall Fase 2: Profissional (Auto-seleção se houver apenas uma opção)
   343→  useEffect(() => {
   344→    if (profInitialized.current || !isOpen || !servicoSelecionado || profissionaisFiltrados.length !== 1) return;
   345→    
   346→    setProfissionalSelecionado(profissionaisFiltrados[0].id);
   347→    profInitialized.current = true;
   348→  }, [profissionaisFiltrados, servicoSelecionado, isOpen]);
   349→
   350→  // Waterfall Fase 3: Horário (Auto-seleção se houver apenas uma opção)
   351→  useEffect(() => {
   352→    if (slotInitialized.current || !isOpen || !profissionalSelecionado || horariosDisponiveis.length !== 1) return;
   353→    
   354→    const singleSlot = horariosDisponiveis.find(h => h.available);
   355→    if (singleSlot) {
   356→      setHorarioSelecionado(singleSlot.slot);
   357→      slotInitialized.current = true;
   358→    }
   359→  }, [horariosDisponiveis, profissionalSelecionado, isOpen]);
   360→
   361→  // Reset de refs ao trocar serviço manualmente (se o usuário decidir mudar após a auto-seleção)
   362→  useEffect(() => {
   363→    if (!isOpen) return;
   364→    // Se o serviço mudar, permitimos que as fases subsequentes rodem de novo se houver apenas uma opção
   365→    profInitialized.current = false;
   366→    slotInitialized.current = false;
   367→  }, [servicoSelecionado]);
   368→
   369→  // Filter professionals based on selected service (Optimized: single API call)
   370→  useEffect(() => {
   371→    let active = true;
   372→
   373→    const filterProfessionalsByService = async (): Promise<void> => {
   374→      if (!isOpen) return;
   375→
   376→      if (!servicoSelecionado) {
   377→        setProfissionaisFiltrados(profissionais);
   378→        return;
   379→      }
   380→
   381→      setLoadingProfissionais(true);
   382→
   383→      try {
   384→        // Use optimized endpoint to get only professionals that offer this service
   385→        const professionalsWithService = await userService.listProfessionalsByService(
   386→          servicoSelecionado
   387→        );
   388→
   389→        if (!active) return;
   390→
   391→        // Map the IDs from the optimized call to the local professional objects
   392→        const allowedIds = new Set(professionalsWithService.map((p: any) => p.id));
   393→        const filtered = profissionais.filter((p) => allowedIds.has(p.id));
   394→
   395→        setProfissionaisFiltrados(filtered);
   396→
   397→        // Clear professional selection if they don't offer the new service
   398→        if (
   399→          profissionalSelecionado && 
   400→          !allowedIds.has(profissionalSelecionado)
   401→        ) {
   402→          setProfissionalSelecionado("");
   403→        }
   404→      } catch (error) {
   405→        console.error("[FILTRO] Erro ao filtrar profissionais:", error);
   406→        if (active) setProfissionaisFiltrados(profissionais);
   407→      } finally {
   408→        if (active) setLoadingProfissionais(false);
   409→      }
   410→    };
   411→
   412→    filterProfessionalsByService();
   413→
   414→    return () => {
   415→      active = false;
   416→    };
   417→  }, [servicoSelecionado, profissionais, isOpen]);
   418→
   419→  // Fetch available time slots when professional, service or date are selected
   420→  useEffect(() => {
   421→    const fetchHorarios = async (): Promise<void> => {
   422→      if (
   423→        !profissionalSelecionado ||
   424→        !servicoSelecionado ||
   425→        !dataSelecionada ||
   426→        !isOpen
   427→      ) {
   428→        setHorariosDisponiveis([]);
   429→        return;
   430→      }
   431→
   432→      setLoadingHorarios(true);
   433→      try {
   434→        const availability = await appointmentService.getAvailability({
   435→          date: dataSelecionada,
   436→          professionalId: profissionalSelecionado,
   437→          serviceId: servicoSelecionado,
   438→          intervalMinutes: 15,
   439→        });
   440→
   441→        // API pode retornar slots ou availableSlots
   442→        const slotsData =
   443→          availability.slots ||
   444→          availability.availableSlots?.map(({ start, end }) => ({
   445→            startTime: start,
   446→            endTime: end,
   447→            available: true,
   448→          })) ||
   449→          [];
   450→
   451→        const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   452→        const horarios = slotsData.map((slot) => {
   453→          // Converter horário UTC para timezone do salão
   454→          const slotLabel = formatUTCToLocal(
   455→            slot.startTime,
   456→            salonTimezone,
   457→            "HH:mm"
   458→          );
   459→
   460→          // Usar o valor de available retornado pela API
   461→          return { slot: slotLabel, available: slot.available !== false };
   462→        });
   463→
   464→        setHorariosDisponiveis(horarios);
   465→
   466→        // Se o horário inicial está disponível, mantê-lo selecionado
   467→        const horarioInicialDisponivel = horarios.find(
   468→          ({ slot, available }) => slot === horarioInicio && available
   469→        );
   470→
   471→        if (horarioInicialDisponivel) {
   472→          setHorarioSelecionado(horarioInicio);
   473→        } else {
   474→          // Tenta selecionar o primeiro horário DISPONÍVEL
   475→          const primeiroDisponivel = horarios.find((h) => h.available);
   476→          if (primeiroDisponivel) {
   477→            setHorarioSelecionado(primeiroDisponivel.slot);
   478→          } else {
   479→            setHorarioSelecionado("");
   480→          }
   481→        }
   482→      } catch (error) {
   483→        console.error("[ModalNovoAgendamento] Error fetching horarios:", error);
   484→        setHorariosDisponiveis([]);
   485→        setHorarioSelecionado("");
   486→      } finally {
   487→        setLoadingHorarios(false);
   488→      }
   489→    };
   490→
   491→    fetchHorarios();
   492→  }, [
   493→    profissionalSelecionado,
   494→    servicoSelecionado,
   495→    dataSelecionada,
   496→    isOpen,
   497→    horarioInicio,
   498→    selectedSalon?.timezone,
   499→  ]);
   500→
   501→  // Fetch professional-specific service configuration
   502→  useEffect(() => {
   503→    const fetchProfessionalConfig = async (): Promise<void> => {
   504→      if (!profissionalSelecionado || !servicoSelecionado || !isOpen) {
   505→        setProfessionalServiceConfig(null);
   506→        return;
   507→      }
   508→
   509→      try {
   510→        const userServices = await serviceService.getUserServices(
   511→          profissionalSelecionado
   512→        );
   513→
   514→        setServicos((currentServicos) =>
   515→          currentServicos.map((userServico) => {
   516→            const userService = userServices.find(
   517→              (userServico) => userServico.id === servicoSelecionado
   518→            );
   519→
   520→            const newDuration =
   521→              userService?.duration > 0
   522→                ? userService?.duration
   523→                : userServico.duracao;
   524→
   525→            const newPrice = userService?.price
   526→              ? Number(String(userService?.price).replace(",", "."))
   527→              : userServico.preco;
   528→
   529→            return {
   530→              ...userServico,
   531→              preco: newPrice,
   532→              duracao: newDuration,
   533→            };
   534→          })
   535→        );
   536→
   537→        const serviceConfig = userServices.find(
   538→          (us: any) => us.service_id === servicoSelecionado
   539→        );
   540→
   541→        if (serviceConfig) {
   542→          setProfessionalServiceConfig({
   543→            customDuration: serviceConfig.custom_duration,
   544→            customPrice: serviceConfig.custom_price,
   545→          });
   546→        } else {
   547→          setProfessionalServiceConfig(null);
   548→        }
   549→      } catch (error) {
   550→        console.error(
   551→          "[ModalNovoAgendamento] Error fetching professional config:",
   552→          error
   553→        );
   554→        setProfessionalServiceConfig(null);
   555→      }
   556→    };
   557→
   558→    fetchProfessionalConfig();
   559→  }, [profissionalSelecionado, servicoSelecionado, isOpen]);
   560→
   561→  // Calculate effective duration based on professional config or service default
   562→  const getEffectiveDuration = (): number => {
   563→    const servico = servicos.find((s) => s.id === servicoSelecionado);
   564→
   565→    // Priority: 1. Professional custom duration, 2. Service duration (salon or default)
   566→    if (professionalServiceConfig?.customDuration) {
   567→      return professionalServiceConfig.customDuration;
   568→    }
   569→
   570→    return servico?.duracao || 0;
   571→  };
   572→
   573→  const podeAgendar = (): boolean => {
   574→    // Validar se o horário selecionado está realmente disponível
   575→    const isHorarioValido = horariosDisponiveis.find(
   576→      (h) => h.slot === horarioSelecionado
   577→    )?.available;
   578→
   579→    return !!(
   580→      clienteSelecionado &&
   581→      servicoSelecionado &&
   582→      profissionalSelecionado &&
   583→      dataSelecionada &&
   584→      horarioSelecionado &&
   585→      isHorarioValido
   586→    );
   587→  };
   588→
   589→  const handleClose = (): void => {
   590→    if (!isSaving) {
   591→      const completedSteps = [clienteSelecionado, servicoSelecionado, profissionalSelecionado, dataSelecionada, horarioSelecionado]
   592→        .filter(Boolean).length;
   593→      if (completedSteps > 0) {
   594→        analytics.trackEvent("appointment_modal_abandoned", {
   595→          completed_steps: completedSteps,
   596→          has_client: !!clienteSelecionado,
   597→          has_service: !!servicoSelecionado,
   598→          has_professional: !!profissionalSelecionado,
