import { trackSeverinoEvent } from "@/services/severinoService";
import { Button } from "@/components/ui/button";
import { Calendar as CalendarComponent } from "@/components/ui/calendar";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
} from "@/components/ui/drawer";
import { useIsMobile } from "@/hooks/useMediaQuery";
import { Label } from "@/components/ui/label";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { useAuth } from "@/contexts/AuthContext";
import { useSelectedSalon } from "@/hooks/useSelectedSalon";
import { cn } from "@/lib/utils";
import { agendaService } from "@/services/agendaService";
import { appointmentService } from "@/services/appointmentService";
import { clientService } from "@/services/clientService";
import { serviceService } from "@/services/serviceService";
import { userService } from "@/services/userService";
import { AppointmentStatus } from "@/types/appointment";
import { convertLocalToUTC, formatUTCToLocal } from "@/utils/dateTimeHelpers";
import { getUserDisplayName } from "@/utils/userHelpers";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { Calendar as Calendar, Check as Check, ChevronDown, Plus as Plus, UserPlus as UserPlus, X as X } from "lucide-react";
import { useEffect, useRef, useState } from "react";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import { formatPhone, cleanPhone } from "@/utils/clientHelpers";
import { analytics } from "@/lib/analytics";

interface ModalNovoAgendamentoProps {
  isOpen: boolean;
  onClose: () => void;
  profissionalId?: string;
  data: string;
  horarioInicio: string;
  initialClientId?: string;
  onAppointmentCreated?: (appointment: { id: string; date: string; time: string; professionalId: string }) => void;
}

interface Cliente {
  id: string;
  nome: string;
  telefone: string;
}

interface Servico {
  id: string;
  nome: string;
  duracao: number;
  preco: number;
}

interface ProfessionalServiceConfig {
  customDuration?: number;
  customPrice?: number;
}

interface Profissional {
  id: string;
  nome: string;
  name: string;
  nickname?: string;
}

// Helper para converter string yyyy-MM-dd em objeto Date local sem problemas de timezone
const parseLocalDate = (dateStr: string): Date | null => {
  if (!dateStr) return null;
  const [year, month, day] = dateStr.split("-").map(Number);
  if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
  return new Date(year, month - 1, day);
};

export function ModalNovoAgendamento({
  isOpen,
  onClose,
  profissionalId,
  data,
  horarioInicio,
  initialClientId,
  onAppointmentCreated,
}: ModalNovoAgendamentoProps): JSX.Element {
  const { selectedSalon } = useSelectedSalon();
  const { user } = useAuth();
  const isMobile = useIsMobile();
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Estados para dados da API
  const [clientes, setClientes] = useState<Cliente[]>([]);
  const [servicos, setServicos] = useState<Servico[]>([]);
  const [servicosFiltrados, setServicosFiltrados] = useState<Servico[]>([]);
  const [profissionais, setProfissionais] = useState<Profissional[]>([]);
  const [profissionaisFiltrados, setProfissionaisFiltrados] = useState<Profissional[]>([]);
  const [loadingProfissionais, setLoadingProfissionais] = useState(false);
  const [loadingServicos, setLoadingServicos] = useState(false);
  const [horariosDisponiveis, setHorariosDisponiveis] = useState<
    { slot: string; available: boolean }[]
  >([]);
  const [salonOpeningHours, setSalonOpeningHours] = useState<any[]>([]);
  const [loadingHorarios, setLoadingHorarios] = useState(false);
  const [professionalServiceConfig, setProfessionalServiceConfig] =
    useState<ProfessionalServiceConfig | null>(null);

  // Estados do formulário
  const [clienteSelecionado, setClienteSelecionado] = useState<string>(initialClientId || "");
  const [servicoSelecionado, setServicoSelecionado] = useState<string>("");
  const [profissionalSelecionado, setProfissionalSelecionado] =
    useState<string>(profissionalId || "");
  const [dataSelecionada, setDataSelecionada] = useState<string>(
    data ? (typeof data === 'string' ? data : format(data, "yyyy-MM-dd")) : ""
  );
  const [horarioSelecionado, setHorarioSelecionado] = useState<string>(horarioInicio);
  const [precoProfissional, setPrecoProfissional] = useState<number | null>(
    null
  );

  // Estados dos popovers
  const [openCliente, setOpenCliente] = useState(false);
  const [openServico, setOpenServico] = useState(false);
  const [openProfissional, setOpenProfissional] = useState(false);
  const [openHorario, setOpenHorario] = useState(false);

  // Estados para cadastro simplificado de cliente
  const [isModoCadastroCliente, setIsModoCadastroCliente] = useState(false);
  const [novoCliente, setNovoCliente] = useState({ nome: "", telefone: "" });
  const [isCriandoCliente, setIsCriandoCliente] = useState(false);

  // Refs para controle de inicialização em cascata (Onboarding)
  const serviceInitialized = useRef(false);
  const profInitialized = useRef(false);
  const slotInitialized = useRef(false);
  // Função para obter mensagem de validação de data
  const getDateValidationMessage = (): string | null => {
    if (!dataSelecionada) return null;

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const selectedDateObj = parseLocalDate(dataSelecionada);

    if (!selectedDateObj || isNaN(selectedDateObj.getTime())) {
      return "Data inválida";
    }

    if (selectedDateObj < today) {
      return "Data não pode ser anterior a hoje";
    }

    return null;
  };

  // Track modal open
  useEffect(() => {
    if (!isOpen) return;
    analytics.trackEvent("appointment_modal_opened", {
      has_preselected_professional: !!profissionalId,
      has_preselected_time: !!horarioInicio,
    });
  }, [isOpen]);

  // Fetch data from API
  useEffect(() => {
    const fetchData = async (): Promise<void> => {
      const salonId =
        selectedSalon?.id || localStorage.getItem("selectedSalonId");

      if (!isOpen || !salonId) {
        return;
      }

      setIsLoading(true);
      setIsModoCadastroCliente(false);
      setNovoCliente({ nome: "", telefone: "" });

      try {
        // Sempre buscar dados frescos quando o modal abrir
        const [
          servicesResponse,
          professionalsResponse,
          clientsResponse,
          salonHoursResponse,
        ] = await Promise.all([
          serviceService.getBookableServices(),
          userService.list({
            role: "professional" as any,
            salonId,
          }),
          clientService.list({
            limit: "100",
            sortBy: "name",
            sortOrder: "ASC",
          }),
          agendaService.getSalonOperatingHours(salonId),
        ]);

        // Inicializar servicosFiltrados com todos os serviços
        const allServices = (servicesResponse || [])
          .filter((s) => s?.duration && s?.duration > 0)
          .map((s) => ({
            id: s.id,
            nome: s.name,
            duracao: s.duration,
            preco:
              typeof s.price === "string" ? parseFloat(s.price) : s.price,
          }));

        setServicos(allServices);
        setServicosFiltrados(allServices);

        setProfissionais(
          (professionalsResponse?.data || []).map((p) => ({
            id: p.id,
            nome: p.name,
            name: p.name,
            nickname: p.nickname,
          }))
        );

        setClientes(
          (clientsResponse?.data || []).map((c) => ({
            id: c.id,
            nome: c.name,
            telefone: c.phone,
          }))
        );

        // Processar horários do salão
        if (salonHoursResponse && salonHoursResponse.openingHours) {
          setSalonOpeningHours(salonHoursResponse.openingHours);
        }
      } catch (error) {
        console.error("[ModalNovoAgendamento] Error fetching data:", error);
        toast.error("Erro ao carregar dados");
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, [isOpen, selectedSalon?.id, user?.id]);

  // Filter services based on selected professional
  useEffect(() => {
    const filterServicesByProfessional = async () => {
      // If no professional selected, show all services
      if (!profissionalSelecionado) {
        setServicosFiltrados(servicos);
        return;
      }

      setLoadingServicos(true);
      try {
        // Fetch services for the selected professional
        const userServices = await userService.getUserServices(
          profissionalSelecionado
        );

        // Filter the full service list to only include those offered by the professional
        const filteredServices = servicos.filter((service) => {
          // Check if professional has this service associated and active
          const userService = userServices.find(
            (us: any) => {
              const matchesService =
                us.serviceId === service.id ||
                us.id === service.id ||
                us.service_id === service.id;

              const isActive = us.isActive !== false && us.is_active !== false;

              return matchesService && isActive;
            }
          );
          return !!userService;
        });

        // Set the filtered list
        setServicosFiltrados(filteredServices);

        // If a service was already selected but is not offered by this professional, clear selection
        if (
          servicoSelecionado &&
          !filteredServices.some((s) => s.id === servicoSelecionado)
        ) {
          setServicoSelecionado("");
          toast.info(
            "Serviço desmarcado pois não é oferecido pelo profissional selecionado"
          );
        }
      } catch (error) {
        console.error("Error filtering services by professional:", error);
        // On error, fallback to showing all services to avoid blocking the user
        setServicosFiltrados(servicos);
      } finally {
        setLoadingServicos(false);
      }
    };

    if (isOpen) {
      filterServicesByProfessional();
    }
  }, [profissionalSelecionado, servicos, isOpen]);

  // Auto-seleção de cliente único
  useEffect(() => {
    if (!isOpen || clienteSelecionado || clientes.length !== 1) return;
    setClienteSelecionado(clientes[0].id);
  }, [clientes, isOpen, clienteSelecionado]);

  // Waterfall Fase 1: Serviço (Auto-seleção se houver apenas uma opção)
  useEffect(() => {
    if (serviceInitialized.current || !isOpen || servicosFiltrados.length !== 1) return;

    setServicoSelecionado(servicosFiltrados[0].id);
    serviceInitialized.current = true;
  }, [servicosFiltrados, isOpen]);

  // Waterfall Fase 2: Profissional (Auto-seleção se houver apenas uma opção)
  useEffect(() => {
    if (profInitialized.current || !isOpen || !servicoSelecionado || profissionaisFiltrados.length !== 1) return;

    setProfissionalSelecionado(profissionaisFiltrados[0].id);
    profInitialized.current = true;
  }, [profissionaisFiltrados, servicoSelecionado, isOpen]);

  // Waterfall Fase 3: Horário (Auto-seleção se houver apenas uma opção)
  useEffect(() => {
    if (slotInitialized.current || !isOpen || !profissionalSelecionado || horariosDisponiveis.length !== 1) return;

    const singleSlot = horariosDisponiveis.find(h => h.available);
    if (singleSlot) {
      setHorarioSelecionado(singleSlot.slot);
      slotInitialized.current = true;
    }
  }, [horariosDisponiveis, profissionalSelecionado, isOpen]);

  // Reset de refs ao trocar serviço manualmente (se o usuário decidir mudar após a auto-seleção)
  useEffect(() => {
    if (!isOpen) return;
    // Se o serviço mudar, permitimos que as fases subsequentes rodem de novo se houver apenas uma opção
    profInitialized.current = false;
    slotInitialized.current = false;
  }, [servicoSelecionado]);

  // Filter professionals based on selected service (Optimized: single API call)
  useEffect(() => {
    let active = true;

    const filterProfessionalsByService = async (): Promise<void> => {
      if (!isOpen) return;

      if (!servicoSelecionado) {
        setProfissionaisFiltrados(profissionais);
        return;
      }

      setLoadingProfissionais(true);

      try {
        // Use optimized endpoint to get only professionals that offer this service
        const professionalsWithService = await userService.listProfessionalsByService(
          servicoSelecionado
        );

        if (!active) return;

        // Map the IDs from the optimized call to the local professional objects
        const allowedIds = new Set(professionalsWithService.map((p: any) => p.id));
        const filtered = profissionais.filter((p) => allowedIds.has(p.id));

        setProfissionaisFiltrados(filtered);

        // Clear professional selection if they don't offer the new service
        if (
          profissionalSelecionado && 
          !allowedIds.has(profissionalSelecionado)
        ) {
          setProfissionalSelecionado("");
        }
      } catch (error) {
        console.error("[FILTRO] Erro ao filtrar profissionais:", error);
        if (active) setProfissionaisFiltrados(profissionais);
      } finally {
        if (active) setLoadingProfissionais(false);
      }
    };

    filterProfessionalsByService();

    return () => {
      active = false;
    };
  }, [servicoSelecionado, profissionais, isOpen]);

  // Fetch available time slots when professional, service or date are selected
  useEffect(() => {
    const fetchHorarios = async (): Promise<void> => {
      if (
        !profissionalSelecionado ||
        !servicoSelecionado ||
        !dataSelecionada ||
        !isOpen
      ) {
        setHorariosDisponiveis([]);
        return;
      }

      setLoadingHorarios(true);
      try {
        const availability = await appointmentService.getAvailability({
          date: dataSelecionada,
          professionalId: profissionalSelecionado,
          serviceId: servicoSelecionado,
          intervalMinutes: 15,
        });

        // API pode retornar slots ou availableSlots
        const slotsData =
          availability.slots ||
          availability.availableSlots?.map(({ start, end }) => ({
            startTime: start,
            endTime: end,
            available: true,
          })) ||
          [];

        const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
        const horarios = slotsData.map((slot) => {
          // Converter horário UTC para timezone do salão
          const slotLabel = formatUTCToLocal(
            slot.startTime,
            salonTimezone,
            "HH:mm"
          );

          // Usar o valor de available retornado pela API
          return { slot: slotLabel, available: slot.available !== false };
        });

        setHorariosDisponiveis(horarios);

        // Se o horário inicial está disponível, mantê-lo selecionado
        const horarioInicialDisponivel = horarios.find(
          ({ slot, available }) => slot === horarioInicio && available
        );

        if (horarioInicialDisponivel) {
          setHorarioSelecionado(horarioInicio);
        } else {
          // Tenta selecionar o primeiro horário DISPONÍVEL
          const primeiroDisponivel = horarios.find((h) => h.available);
          if (primeiroDisponivel) {
            setHorarioSelecionado(primeiroDisponivel.slot);
          } else {
            setHorarioSelecionado("");
          }
        }
      } catch (error) {
        console.error("[ModalNovoAgendamento] Error fetching horarios:", error);
        setHorariosDisponiveis([]);
        setHorarioSelecionado("");
      } finally {
        setLoadingHorarios(false);
      }
    };

    fetchHorarios();
  }, [
    profissionalSelecionado,
    servicoSelecionado,
    dataSelecionada,
    isOpen,
    horarioInicio,
    selectedSalon?.timezone,
  ]);

  // Fetch professional-specific service configuration
  useEffect(() => {
    const fetchProfessionalConfig = async (): Promise<void> => {
      if (!profissionalSelecionado || !servicoSelecionado || !isOpen) {
        setProfessionalServiceConfig(null);
        return;
      }

      try {
        const userServices = await serviceService.getUserServices(
          profissionalSelecionado
        );

        setServicos((currentServicos) =>
          currentServicos.map((userServico) => {
            const userService = userServices.find(
              (userServico) => userServico.id === servicoSelecionado
            );

            const newDuration =
              userService?.duration > 0
                ? userService?.duration
                : userServico.duracao;

            const newPrice = userService?.price
              ? Number(String(userService?.price).replace(",", "."))
              : userServico.preco;

            return {
              ...userServico,
              preco: newPrice,
              duracao: newDuration,
            };
          })
        );

        const serviceConfig = userServices.find(
          (us: any) => us.service_id === servicoSelecionado
        );

        if (serviceConfig) {
          setProfessionalServiceConfig({
            customDuration: serviceConfig.custom_duration,
            customPrice: serviceConfig.custom_price,
          });
        } else {
          setProfessionalServiceConfig(null);
        }
      } catch (error) {
        console.error(
          "[ModalNovoAgendamento] Error fetching professional config:",
          error
        );
        setProfessionalServiceConfig(null);
      }
    };

    fetchProfessionalConfig();
  }, [profissionalSelecionado, servicoSelecionado, isOpen]);

  // Calculate effective duration based on professional config or service default
  const getEffectiveDuration = (): number => {
    const servico = servicos.find((s) => s.id === servicoSelecionado);

    // Priority: 1. Professional custom duration, 2. Service duration (salon or default)
    if (professionalServiceConfig?.customDuration) {
      return professionalServiceConfig.customDuration;
    }

    return servico?.duracao || 0;
  };

  const podeAgendar = (): boolean => {
    // Validar se o horário selecionado está realmente disponível
    const isHorarioValido = horariosDisponiveis.find(
      (h) => h.slot === horarioSelecionado
    )?.available;

    return !!(
      clienteSelecionado &&
      servicoSelecionado &&
      profissionalSelecionado &&
      dataSelecionada &&
      horarioSelecionado &&
      isHorarioValido
    );
  };

  const handleClose = (): void => {
    if (!isSaving) {
      const completedSteps = [clienteSelecionado, servicoSelecionado, profissionalSelecionado, dataSelecionada, horarioSelecionado]
        .filter(Boolean).length;
      if (completedSteps > 0) {
        analytics.trackEvent("appointment_modal_abandoned", {
          completed_steps: completedSteps,
          has_client: !!clienteSelecionado,
          has_service: !!servicoSelecionado,
          has_professional: !!profissionalSelecionado,
          has_date: !!dataSelecionada,
          has_time: !!horarioSelecionado,
        });
      }
    }
    onClose();
  };

  const handleAgendar = async (): Promise<void> => {
    if (!selectedSalon?.id || !podeAgendar()) return;

    setIsSaving(true);
    try {
      const servico = servicos.find((s) => s.id === servicoSelecionado);
      if (!servico) return;

      // Get effective duration (professional custom or service default)
      const effectiveDuration = getEffectiveDuration();

      // Converter horário local do salão para UTC
      const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
      const appointmentDateTime = convertLocalToUTC(
        dataSelecionada,
        horarioSelecionado,
        salonTimezone
      );

      const endDateTime = new Date(
        appointmentDateTime.getTime() + effectiveDuration * 60 * 1000
      );

      // Backend will automatically calculate:
      // - Price from professional-specific pricing, or service default price
      // - Duration from professional-specific duration, or service default duration
      const appointmentPayload = {
        clientId: clienteSelecionado,
        professionalId: profissionalSelecionado,
        serviceId: servicoSelecionado,
        startTime: appointmentDateTime.toISOString(),
        endTime: endDateTime.toISOString(),
        status: AppointmentStatus.SCHEDULED,
        // Don't send price - let backend calculate from professional or service pricing
      };

      const created = await appointmentService.create(appointmentPayload);

      toast.success("Agendamento criado com sucesso");

      trackSeverinoEvent('agendamento_realizado', { description: 'Agendamento criado via agenda interna' });

      // Call refresh callback before closing
      if (onAppointmentCreated) {
        onAppointmentCreated({
          id: created.id,
          date: dataSelecionada,
          time: horarioSelecionado,
          professionalId: profissionalSelecionado,
        });
      }

      onClose();
    } catch (error: any) {
      const errorMsg =
        error.response?.data?.message || "Erro ao criar agendamento";
      analytics.trackEvent("appointment_creation_failed", { error_type: error.response?.data?.message || "unknown" });
      toast.error(errorMsg);
    } finally {
      setIsSaving(false);
    }
  };

  const formBody = isLoading ? (
          <div className="flex items-center justify-center py-12">
            <LoadingSpinner size="md" />
          </div>
        ) : (
          <div className="space-y-6">
            {/* Step 1: Cliente */}
