                <div
                  className={cn(
                    "w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0",
                    clienteSelecionado
                      ? "bg-primary text-primary-foreground"
                      : "bg-muted border border-border"
                  )}
                >
                  {clienteSelecionado && <Check className="w-2.5 h-2.5 text-primary-foreground" />}
                </div>
                <Label>Selecione o Cliente</Label>
              </div>

              <div>
                <Popover
                  open={openCliente}
                  onOpenChange={setOpenCliente}
                  modal={false}
                >
                  <PopoverTrigger asChild>
                    <button
                      type="button"
                      role="combobox"
                      aria-expanded={openCliente}
                      disabled={isLoading}
                      className={cn(
                        "flex h-[40px] w-full items-center justify-between rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                      )}
                    >
                      <span className={cn(!clienteSelecionado && !isLoading && "text-muted-foreground")}>
                        {isLoading ? (
                          <span className="flex items-center gap-2">
                            <LoadingSpinner size="sm" inline />
                            Carregando clientes...
                          </span>
                        ) : clienteSelecionado ? (
                          clientes.find((c) => c.id === clienteSelecionado)?.nome
                        ) : (
                          "Buscar e selecionar cliente..."
                        )}
                      </span>
                      <ChevronDown className="h-4 w-4 opacity-50 flex-shrink-0" />
                    </button>
                  </PopoverTrigger>
                  <PopoverContent
                    className="p-1 overflow-hidden pointer-events-auto"
                    align="start"
                    sideOffset={4}
                    style={{ width: "var(--radix-popover-trigger-width)" }}
                    onWheel={(e) => e.stopPropagation()}
                  >
                    <Command>
                      {!isModoCadastroCliente && (
                        <CommandInput placeholder="Buscar cliente..." />
                      )}
                      <CommandList>
                        {isModoCadastroCliente ? (
                          <div className="p-4 space-y-4">
                            <h4 className="font-medium text-body flex items-center gap-2">
                              <UserPlus className="h-4 w-4" />
                              Novo Cliente
                            </h4>
                            <div className="space-y-3">
                              <div className="space-y-1">
                                <Label htmlFor="new-client-name" className="text-xs">Nome *</Label>
                                <Input
                                  id="new-client-name"
                                  placeholder="Nome completo"
                                  value={novoCliente.nome}
                                  onChange={(e) => setNovoCliente(prev => ({ ...prev, nome: e.target.value }))}
                                  className="h-9"
                                  autoFocus
                                />
                              </div>
                              <div className="space-y-1">
                                <Label htmlFor="new-client-phone" className="text-xs">Telefone *</Label>
                                <Input
                                  id="new-client-phone"
                                  placeholder="(00) 00000-0000"
                                  value={novoCliente.telefone}
                                  onChange={(e) => setNovoCliente(prev => ({ ...prev, telefone: formatPhone(e.target.value) }))}
                                  className="h-9"
                                />
                              </div>
                            </div>
                            <div className="flex gap-2 pt-2">
                              <Button
                                variant="outline"
                                size="sm"
                                className="flex-1"
                                onClick={() => setIsModoCadastroCliente(false)}
                                disabled={isCriandoCliente}
                              >
                                Cancelar
                              </Button>
                              <Button
                                size="sm"
                                className="flex-1"
                                onClick={async () => {
                                  if (!novoCliente.nome.trim()) {
                                    toast.error("Nome é obrigatório");
                                    return;
                                  }
                                  const cleanedPhone = cleanPhone(novoCliente.telefone);
                                  if (cleanedPhone.length < 10) {
                                    toast.error("Por favor, insira um telefone válido com DDD");
                                    return;
                                  }
                                  setIsCriandoCliente(true);
                                  try {
                                    const created = await clientService.create({
                                      name: novoCliente.nome,
                                      phone: cleanPhone(novoCliente.telefone),
                                      salonId: selectedSalon?.id
                                    });

                                    // Adicionar o novo cliente na lista local para evitar requisição extra
                                    const novo = {
                                      id: created.id,
                                      nome: created.name,
                                      telefone: created.phone
                                    };
                                    setClientes(prev => [novo, ...prev]);
                                    setClienteSelecionado(created.id);
                                    setOpenCliente(false);
                                    setIsModoCadastroCliente(false);
                                    setNovoCliente({ nome: "", telefone: "" });
                                  } catch (error: any) {
                                    toast.error(error.message || "Erro ao criar cliente");
                                  } finally {
                                    setIsCriandoCliente(false);
                                  }
                                }}
                                disabled={isCriandoCliente}
                              >
                                {isCriandoCliente ? (
                                  <LoadingSpinner size="sm" inline />
                                ) : (
                                  "Confirmar"
                                )}
                              </Button>
                            </div>
                          </div>
                        ) : (
                          <>
                            <CommandEmpty className="p-0">
                              <div className="p-4 flex flex-col items-center gap-3">
                                <p className="text-body text-muted-foreground text-center">Nenhum cliente encontrado.</p>
                                <Button
                                  variant="secondary"
                                  size="sm"
                                  className="w-full text-xs gap-2"
                                  onClick={() => setIsModoCadastroCliente(true)}
                                >
                                  <UserPlus className="h-3 w-3" />
                                  Cadastrar "{novoCliente.nome || "Novo Cliente"}"
                                </Button>
                              </div>
                            </CommandEmpty>
                            <CommandGroup>
                              <CommandItem
                                onSelect={() => setIsModoCadastroCliente(true)}
                                className="text-[13px] text-primary font-medium gap-2 cursor-pointer pl-3 pr-2"
                              >
                                <Plus className="h-4 w-4" />
                                Cadastrar Novo Cliente
                              </CommandItem>
                              {clientes.map((cliente) => (
                                <CommandItem
                                  key={cliente.id}
                                  value={`${cliente.nome} ${cliente.telefone}`}
                                  onSelect={() => {
                                    setClienteSelecionado(cliente.id);
                                    setOpenCliente(false);
                                  }}
                                  className="text-[13px] pl-8 pr-2"
                                >
                                  <Check
                                    className={cn(
                                      "mr-2 h-4 w-4",
                                      clienteSelecionado === cliente.id
                                        ? "opacity-100"
                                        : "opacity-0"
                                    )}
                                  />
                                  <div className="flex flex-col">
                                    <span className="font-medium">
                                      {cliente.nome}
                                    </span>
                                    <span className="text-body text-muted-foreground">
                                      {cliente.telefone}
                                    </span>
                                  </div>
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </>
                        )}
                      </CommandList>
                    </Command>
                  </PopoverContent>
                </Popover>

              </div>
            </div>

            {/* Step 2: Serviço */}
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <div
                  className={cn(
                    "w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0",
                    servicoSelecionado
                      ? "bg-primary text-primary-foreground"
                      : "bg-muted border border-border"
                  )}
                >
                  {servicoSelecionado && <Check className="w-2.5 h-2.5 text-primary-foreground" />}
                </div>
                <Label>Selecione o Serviço</Label>
              </div>

              <div>
                <Popover
                  open={openServico}
                  onOpenChange={setOpenServico}
                  modal={false}
                >
                  <PopoverTrigger asChild>
                    <button
                      type="button"
                      role="combobox"
                      aria-expanded={openServico}
                      disabled={isLoading || loadingServicos}
                      className={cn(
                        "flex h-[40px] w-full items-center justify-between rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                      )}
                    >
                      {isLoading || loadingServicos ? (
                        <span className="flex items-center gap-2 text-muted-foreground">
                          <LoadingSpinner size="sm" inline />
                          Carregando serviços...
                        </span>
                      ) : servicoSelecionado ? (
                        <div className="flex items-center justify-between w-full gap-2 overflow-hidden">
                          <span className="truncate">
                            {servicosFiltrados.find((s) => s.id === servicoSelecionado)?.nome}
                          </span>
                          <div
                            role="button"
                            tabIndex={0}
                            className="p-1 hover:bg-muted rounded-full cursor-pointer transition-colors shrink-0"
                            onClick={(e) => {
                              e.stopPropagation();
                              setServicoSelecionado("");
                            }}
                            onKeyDown={(e) => {
                              if (e.key === "Enter" || e.key === " ") {
                                e.stopPropagation();
                                setServicoSelecionado("");
                              }
                            }}
                          >
                            <X className="h-4 w-4 opacity-50 hover:opacity-100" />
                          </div>
                        </div>
                      ) : (
                        <span className="text-muted-foreground">Buscar e selecionar serviço...</span>
                      )}
                    </button>
                  </PopoverTrigger>
                  <PopoverContent
                    className="p-1 overflow-hidden pointer-events-auto"
                    align="start"
                    sideOffset={4}
                    style={{ width: "var(--radix-popover-trigger-width)" }}
                    onWheel={(e) => e.stopPropagation()}
                  >
                    <Command>
                      <CommandInput placeholder="Buscar serviço..." />
                      <CommandList>
                        <CommandEmpty>
                          Nenhum serviço encontrado.
                        </CommandEmpty>
                        <CommandGroup>
                          {servicosFiltrados.map((servico) => (
                            <CommandItem
                              key={servico.id}
                              value={servico.nome}
                              onSelect={() => {
                                setServicoSelecionado(servico.id);
                                setOpenServico(false);
                              }}
                              className="text-[13px] pl-8 pr-2"
                            >
                              <Check
                                className={cn(
                                  "mr-2 h-4 w-4",
                                  servicoSelecionado === servico.id
                                    ? "opacity-100"
                                    : "opacity-0"
                                )}
                              />
                              <div className="flex flex-col">
                                <span className="font-medium">
                                  {servico.nome}
                                </span>
                                <span className="text-body text-muted-foreground">
                                  {servico.duracao} min • R${" "}
                                  {servico.preco.toFixed(2)}
                                </span>
                              </div>
                            </CommandItem>
                          ))}
                        </CommandGroup>
                      </CommandList>
                    </Command>
                  </PopoverContent>
                </Popover>

