                      role="combobox"
                      aria-expanded={openProfissional}
                      disabled={isLoading || loadingProfissionais || !servicoSelecionado}
                      className={cn(
                        "flex h-[40px] w-full items-center justify-between rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                      )}
                    >
                      {isLoading || loadingProfissionais ? (
