          <DrawerTitle>Novo Agendamento</DrawerTitle>
        </DrawerHeader>
        <div className="flex-1 min-h-0 overflow-y-auto">
          {formBody}
        </div>
        <div className="flex gap-3 px-4 py-6 border-t border-border flex-shrink-0">
          <Button variant="outline" className="flex-1" onClick={onClose}>Cancelar</Button>
          <Button
            onClick={handleAgendar}
            disabled={!podeAgendar() || isSaving || !selectedSalon?.active}
            className="flex-1 bg-primary hover:bg-primary/90 text-primary-foreground disabled:opacity-50"
          >
            {isSaving ? (
              <>
                <LoadingSpinner size="sm" inline className="mr-2" />
                Agendando...
              </>
            ) : (
              "Criar agendamento"
            )}
          </Button>
        </div>
      </DrawerContent>
    </Drawer>
  ) : (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent
        className="w-[95vw] md:max-w-lg flex flex-col gap-0 max-h-[90dvh]"
        onInteractOutside={(e) => e.preventDefault()}
      >
        <DialogHeader className="border-b pb-3 shrink-0">
          <DialogTitle>Novo Agendamento</DialogTitle>
          <DialogDescription>
            Preencha os dados abaixo para criar um novo agendamento.
          </DialogDescription>
        </DialogHeader>
        <DialogBody>
          {formBody}
        </DialogBody>
        <DialogFooter className="border-t pt-6 shrink-0">
          <Button variant="outline" onClick={onClose}>Cancelar</Button>
          <Button
            onClick={handleAgendar}
            disabled={!podeAgendar() || isSaving || !selectedSalon?.active}
          >
            {isSaving ? (
              <>
                <LoadingSpinner size="sm" inline className="mr-2" />
                Agendando...
              </>
            ) : (
              "Criar agendamento"
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

