   641→  const getProfessionalWorkingHours = (
   642→    professionalId: string,
   643→    date: string
   644→  ) => {
   645→    const professional = professionals.find((p) => p.id === professionalId);
   646→    if (
   647→      !professional ||
   648→      !professional.workingHours ||
   649→      !Array.isArray(professional.workingHours) ||
   650→      professional.workingHours.length === 0
   651→    ) {
   652→      return null;
   653→    }
   654→
   655→    const dayOfWeek = new Date(date).getDay();
   656→    const dayNames = [
   657→      "sunday",
   658→      "monday",
   659→      "tuesday",
   660→      "wednesday",
   661→      "thursday",
   662→      "friday",
   663→      "saturday",
   664→    ];
   665→    const dayName = dayNames[dayOfWeek];
   666→
   667→    // Procurar horário específico do profissional para o dia
   668→    const daySchedule = professional.workingHours.find(
   669→      (wh: any) => wh.dayOfWeek === dayName || wh.dayOfWeek === dayOfWeek
   670→    );
   671→
   672→    if (daySchedule && daySchedule.start && daySchedule.end) {
   673→      return {
   674→        start: daySchedule.start,
   675→        end: daySchedule.end,
   676→      };
   677→    }
   678→
   679→    // Fallback para o primeiro horário encontrado
   680→    if (professional.workingHours[0]) {
   681→      return {
   682→        start: professional.workingHours[0].start,
   683→        end: professional.workingHours[0].end,
   684→      };
   685→    }
   686→
   687→    return null;
   688→  };
