   709→        );
   710→
   711→        const slotsFromAPI = Array.isArray(response)
   712→          ? response
   713→          : response.availableSlots || [];
   714→
   715→        // Se a API retornou slots, formatar eles do UTC para o timezone do salão
   716→        if (slotsFromAPI.length > 0) {
   717→          const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   718→
   719→          // Converter slots de ISO UTC para HH:mm no timezone do salão
   720→          const formattedSlots = slotsFromAPI.map((slot) => {
   721→            // Se o slot já está em formato HH:mm, manter
   722→            if (slot.match(/^\d{2}:\d{2}$/)) {
   723→              return slot;
   724→            }
   725→
   726→            // Se está em formato ISO (UTC), converter para o timezone do salão
   727→            return formatUTCToLocal(slot, salonTimezone, "HH:mm");
   728→          });
   729→
   730→          // Se estamos editando, incluir o horário atual como disponível
   731→          if (appointment) {
   732→            const currentTime = formatUTCToLocal(
