   741→          }
   742→
   743→          setAvailableSlots(formattedSlots);
   744→          return;
   745→        }
   746→      } catch (apiError) {
   747→        console.error("Error loading availability from API:", apiError);
   748→        // API fallback
   749→      }
   750→
   751→      // Fallback: gerar slots baseados nos horários do profissional ou salão
