   761→      } else if (salonWorkingHours) {
   762→        workingHours = salonWorkingHours;
   763→      } else {
   764→        workingHours = { start: "09:00", end: "18:00" };
   765→      }
   766→
   767→      // Gerar slots de 15 em 15 minutos
   768→      let generatedSlots = generateTimeSlots(
   769→        workingHours.start,
   770→        workingHours.end,
   771→        15
   772→      );
   773→
   774→      // Filtrar horários passados se for hoje
   775→      const now = new Date();
   776→      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
   777→      // Parse safely
   778→      const selectedDateObj = selectedDate.includes('T') 
