   824→  // Handler: Quando HORÁRIO INICIAL mudar → Recalcula DURAÇÃO (mantém horário final)
   825→  const handleStartTimeChange = (newStartTime: string): void => {
   826→    setEditableStartTime(newStartTime);
   827→
   828→    if (!editableEndTime) return;
   829→
   830→    // Calcular nova duração baseada no novo horário inicial e horário final existente
   831→    const [startHour, startMinute] = newStartTime.split(":").map(Number);
   832→    const [endHour, endMinute] = editableEndTime.split(":").map(Number);
   833→
   834→    const startMinutes = startHour * 60 + startMinute;
   835→    const endMinutes = endHour * 60 + endMinute;
   836→
   837→    let newDuration = endMinutes - startMinutes;
   838→
