interface Professional {
  id: string;
  name: string;
  nickname?: string;
  workingHours?: Array<{
    dayOfWeek?: string | number;
    start: string;
    end: string;
    isOpen?: boolean;
  }>;
}

interface Service {
  id: string;
  name: string;
  duration: number;
  price: number;
}

