                  </div>
                ) : (
                  <Select
                    value={editableStartTime}
                    onValueChange={handleStartTimeChange}
                    disabled={startTimeOptions.length === 0}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione o horário" />
                    </SelectTrigger>
                    <SelectContent>
                      {startTimeOptions.map((time) => (
                        <SelectItem key={time} value={time}>
                          {time}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                )}
                {getTimeValidationMessage() && (
                  <p className="text-[10px] text-destructive font-medium">
                    {getTimeValidationMessage()}
                  </p>
                )}
              </div>

              {/* Duração */}
              <div className="space-y-2">
                <Label htmlFor="duration" className="flex items-center gap-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                  <Clock className="h-3.5 w-3.5" />
                  Duração *
                </Label>
                <Select
                  value={editableDuration.toString()}
                  onValueChange={(value) => handleDurationChange(Number(value))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Selecione a duração" />
                  </SelectTrigger>
                  <SelectContent>
                    {durationOptions.map((duration) => (
                      <SelectItem key={duration} value={duration.toString()}>
                        {duration} minutos{" "}
                        {duration >= 60 &&
                          `(${Math.floor(duration / 60)}h${duration % 60 > 0 ? ` ${duration % 60}min` : ""})`}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Horário Final */}
              <div className="space-y-2">
                <Label htmlFor="endTime" className="flex items-center gap-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                  <Clock className="h-3.5 w-3.5" />
                  Horário Final *
                </Label>
                {loadingHorarios ? (
                  <div className="h-[38px] sm:h-[35px] text-[13px] sm:text-[12px] text-muted-foreground px-3 bg-muted/30 rounded-lg flex items-center gap-2">
                    <LoadingSpinner size="sm" inline />
                    Buscando horários...
                  </div>
                ) : (
                  <Select
                    value={editableEndTime}
                    onValueChange={handleEndTimeChange}
                    disabled={endTimeOptions.length === 0 || !editableStartTime}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione o horário final" />
                    </SelectTrigger>
                    <SelectContent className="max-h-[200px]">
                      {(() => {
                        if (!editableStartTime) {
                          return (
                            <div className="p-2 text-body text-muted-foreground text-center">
                              Selecione o horário inicial primeiro
                            </div>
                          );
                        }

                        const mockedTimes: string[] = [];
                        const [startHour, startMinute] = editableStartTime.split(":").map(Number);
                        const startMinutes = startHour * 60 + startMinute;

                        let maxMinutes = startMinutes + 480; 
                        if (editableEndTime) {
                          const [endHour, endMinute] = editableEndTime.split(":").map(Number);
                          const endMinutes = endHour * 60 + endMinute;
                          maxMinutes = Math.max(endMinutes, startMinutes + 480);
                        }

                        for (let minutes = startMinutes + 15; minutes <= maxMinutes && minutes < 24 * 60; minutes += 15) {
                          const hour = Math.floor(minutes / 60);
                          const minute = minutes % 60;
                          const timeStr = `${hour.toString().padStart(2, "0")}:${minute.toString().padStart(2, "0")}`;
                          mockedTimes.push(timeStr);
                        }

                        const allEndTimes = [...new Set([...mockedTimes, ...endTimeOptions])];
                        allEndTimes.sort();

                        const filteredEndTimes = allEndTimes.filter((time) => {
                          const [endHour, endMinute] = time.split(":").map(Number);
                          const endMinutes = endHour * 60 + endMinute;
                          return endMinutes > startMinutes;
                        });

                        if (filteredEndTimes.length === 0) {
                          return (
                            <div className="p-2 text-body text-muted-foreground text-center">
                              Indisponível após {editableStartTime}
                            </div>
                          );
                        }

                        return filteredEndTimes.map((time) => (
                          <SelectItem key={time} value={time}>
                            {time}
                          </SelectItem>
                        ));
                      })()}
                    </SelectContent>
                  </Select>
                )}
              </div>

              {/* Observações */}
              <div className="space-y-2 col-span-1 md:col-span-2">
                <Label htmlFor="notes" className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Observações</Label>
                <Textarea
                  id="notes"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Informações adicionais sobre este agendamento..."
                  className="salon-input min-h-[100px] resize-none"
                  rows={3}
                />
              </div>

              {/* Aviso se o agendamento já passou */}
              {isAppointmentPast() && (
                <div className="p-3 bg-muted/60 border border-border rounded-lg col-span-1 md:col-span-2">
                  <p className="text-xs text-muted-foreground flex items-center gap-2">
                    <span className="text-base">⚠️</span>
                    Este agendamento já passou. Não é possível fazer alterações.
                  </p>
                </div>
              )}
              </div>
            )}
          </DialogBody>

          <DialogFooter className="border-t pt-6 shrink-0">
            {loadingData || !appointment ? (
              <Button variant="outline" onClick={onClose}>
                Fechar
              </Button>
            ) : !isEditing ? (
              <>
                <Button variant="outline" onClick={onClose}>
                  Fechar
                </Button>
                {!isReserva() && (
                  <>
                    <Button
                      variant="destructive"
                      onClick={() => setShowCancelDialog(true)}
                      disabled={isAppointmentPast() || !selectedSalon?.active}
                    >
                      <Trash2 className="h-4 w-4 mr-2" />
                      Cancelar
                    </Button>
                    <Button
                      onClick={() => setIsEditing(true)}
                      disabled={isAppointmentPast() || !selectedSalon?.active}
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Editar
                    </Button>
                  </>
                )}
              </>
            ) : (
              <>
                <Button
                  variant="outline"
                  onClick={() => setIsEditing(false)}
                  disabled={loading}
                >
                  Voltar
                </Button>
                <Button
                  onClick={handleSubmit}
                  disabled={
                    loading ||
                    isAppointmentPast() ||
                    !selectedClient ||
                    !selectedProfessional ||
                    !selectedService ||
                    !selectedDate ||
                    !selectedTime
                  }
                >
                  {loading ? (
                    <>
                      <LoadingSpinner size="sm" inline className="mr-2" />
                      Salvando...
                    </>
                  ) : (
                    "Salvar Alterações"
                  )}
                </Button>
              </>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Dialog de confirmação de cancelamento */}
      <AlertDialog open={showCancelDialog} onOpenChange={setShowCancelDialog}>
        <AlertDialogContent className="w-[95vw] max-w-[400px] rounded-lg p-6 gap-6"> {/* RESP: AlertDialog adaptado para mobile */}
          <AlertDialogHeader className="text-left">
            <AlertDialogTitle className="text-xl font-bold">Confirmar Cancelamento</AlertDialogTitle>
            <AlertDialogDescription className="text-base pt-2">
              Tem certeza que deseja cancelar este agendamento? Esta ação não
              pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="flex flex-col-reverse sm:flex-row gap-3 sm:gap-2"> {/* RESP: Footer flex-col no mobile */}
            <AlertDialogCancel disabled={cancelLoading} className="w-full sm:w-auto mt-0">
              Voltar
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleCancel}
              disabled={cancelLoading}
              className="w-full sm:w-auto bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {cancelLoading ? (
                <>
                  <LoadingSpinner size="sm" inline className="mr-2" />
                  Cancelando...
                </>
              ) : (
                "Sim, Cancelar Agendamento"
              )}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

