                <Popover modal={false}>
                  <PopoverTrigger asChild>
                    <Button
                      variant="outline"
                      className={cn(
                        "w-full justify-start text-left font-normal h-11",
                        !selectedDate && "text-muted-foreground",
                        getDateValidationMessage() && "border-destructive"
                      )}
                    >
                      <CalendarIcon className="mr-2 h-4 w-4" />
                      {selectedDate ? (
                        format(new Date(selectedDate + "T00:00:00"), "PPP", {
                          locale: ptBR,
                        })
                      ) : (
                        <span>Selecione uma data</span>
                      )}
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-0" align="start">
                    <CalendarComponent
                      mode="single"
                      selected={
                        selectedDate
                          ? new Date(selectedDate + "T00:00:00")
                          : undefined
                      }
                      onSelect={(date) => {
                        if (date) {
                          const newDate = format(date, "yyyy-MM-dd");
                          setSelectedDate(newDate);
                          setSelectedTime(""); // Resetar horário quando mudar a data
                        }
                      }}
                      disabled={(date) => {
                        // Bloquear datas passadas
                        const today = new Date();
                        today.setHours(0, 0, 0, 0);
                        if (date < today) return true;

                        // Bloquear datas em que o salão não está aberto
                        if (salonOpeningHours.length > 0) {
                          const dayOfWeek = date.getDay();
                          const dayNames = [
                            "sunday",
                            "monday",
                            "tuesday",
                            "wednesday",
                            "thursday",
                            "friday",
                            "saturday",
                          ];
                          const dayName = dayNames[dayOfWeek];

                          const daySchedule = salonOpeningHours.find(
                            (schedule) => {
                              const scheduleDayOfWeek =
                                typeof schedule.dayOfWeek === "string"
                                  ? schedule.dayOfWeek.toLowerCase()
                                  : dayNames[schedule.dayOfWeek];
                              return (
                                scheduleDayOfWeek === dayName && schedule.isOpen
                              );
                            }
                          );

                          return !daySchedule;
                        }

                        return false;
                      }}
                      initialFocus
                    />
                  </PopoverContent>
                </Popover>
                {getDateValidationMessage() && (
                  <p className="text-[10px] text-destructive font-medium">
                    {getDateValidationMessage()}
                  </p>
                )}
                {selectedDate && !getDateValidationMessage() && (
                  <p className="text-xs text-muted-foreground mt-1">
                    <span className="font-medium">Data selecionada:</span>{" "}
                    {(() => {
                      const dateObj = selectedDate.includes('T') 
                        ? new Date(selectedDate) 
                        : new Date(selectedDate + "T00:00:00");

                      if (isNaN(dateObj.getTime())) return <span>Data inválida</span>;

                      return format(dateObj, "EEEE, d 'de' MMMM 'de' yyyy", {
                        locale: ptBR,
                      });
                    })()}
                  </p>
                )}
