  }, [isOpen, appointment, selectedSalon?.id]);

  const resetForm = () => {
    setSelectedClient("");
    setSelectedProfessional("");
    setSelectedService("");
    setSelectedDate("");
    setSelectedTime("");
    setNotes("");
    setClients([]);
    setProfessionals([]);
