    90→// Função de busca flexível que funciona com diferentes formatos de texto
    91→const smartSearch = (searchTerm: string, target: string): boolean => {
    92→  if (!searchTerm || !target) return true;
    93→
    94→  const normalizedSearch = normalizeString(searchTerm);
    95→  const normalizedTarget = normalizeString(target);
    96→
