   578→  const generateTimeSlots = (
   579→    startHour: string,
   580→    endHour: string,
   581→    interval: number = 15
   582→  ): string[] => {
   583→    const slots: string[] = [];
   584→    const [startH, startM] = startHour.split(":").map(Number);
   585→    const [endH, endM] = endHour.split(":").map(Number);
   586→
   587→    const startMinutes = startH * 60 + startM;
   588→    const endMinutes = endH * 60 + endM;
   589→
   590→    for (
   591→      let minutes = startMinutes;
   592→      minutes < endMinutes;
   593→      minutes += interval
   594→    ) {
   595→      const hours = Math.floor(minutes / 60);
   596→      const mins = minutes % 60;
   597→      slots.push(
   598→        `${hours.toString().padStart(2, "0")}:${mins
   599→          .toString()
   600→          .padStart(2, "0")}`
   601→      );
   602→    }
   603→
   604→    return slots;
   605→  };
