   792→    setEditableStartTime(newStartTime);
   793→
   794→    if (!editableEndTime) return;
   795→
   796→    // Calcular nova duração baseada no novo horário inicial e horário final existente
   797→    const [startHour, startMinute] = newStartTime.split(":").map(Number);
   798→    const [endHour, endMinute] = editableEndTime.split(":").map(Number);
   799→
   800→    const startMinutes = startHour * 60 + startMinute;
   801→    const endMinutes = endHour * 60 + endMinute;
   802→
   803→    let newDuration = endMinutes - startMinutes;
   804→
   805→    // Se o horário final for menor que o inicial, assumir dia seguinte
   806→    if (newDuration <= 0) {
   807→      newDuration += 24 * 60; // Adicionar 24 horas em minutos
   808→    }
