   826→    const endHour = Math.floor(normalizedEndMinutes / 60);
   827→    const endMinute = normalizedEndMinutes % 60;
   828→
   829→    const newEndTime = `${endHour.toString().padStart(2, "0")}:${endMinute
   830→      .toString()
   831→      .padStart(2, "0")}`;
