    36→import { toast } from "sonner";
    37→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    38→import { appointmentService } from "@/services/appointmentService";
    39→import { userService } from "@/services/userService";
    40→import { serviceService } from "@/services/serviceService";
    41→import { clientService } from "@/services/clientService";
    42→import { agendaService } from "@/services/agendaService";
    43→import { Appointment } from "@/types/appointment";
    44→import { UserRole } from "@/types/user";
    45→import { convertLocalToUTC, formatUTCToLocal } from "@/utils/dateTimeHelpers";
    46→import { getUserDisplayName } from "@/utils/userHelpers";
    47→
    48→interface Professional {
