   576→  const getProfessionalWorkingHours = (
   577→    professionalId: string,
   578→    date: string
   579→  ) => {
   580→    const professional = professionals.find((p) => p.id === professionalId);
   581→    if (
   582→      !professional ||
   583→      !professional.workingHours ||
   584→      !Array.isArray(professional.workingHours) ||
   585→      professional.workingHours.length === 0
   586→    ) {
   587→      return null;
   588→    }
   589→
   590→    const dayOfWeek = new Date(date).getDay();
   591→    const dayNames = [
   592→      "sunday",
   593→      "monday",
   594→      "tuesday",
   595→      "wednesday",
   596→      "thursday",
   597→      "friday",
   598→      "saturday",
   599→    ];
   600→    const dayName = dayNames[dayOfWeek];
   601→
   602→    // Procurar horário específico do profissional para o dia
   603→    const daySchedule = professional.workingHours.find(
   604→      (wh: any) => wh.dayOfWeek === dayName || wh.dayOfWeek === dayOfWeek
   605→    );
   606→
   607→    if (daySchedule && daySchedule.start && daySchedule.end) {
   608→      return {
   609→        start: daySchedule.start,
   610→        end: daySchedule.end,
   611→      };
   612→    }
   613→
   614→    // Fallback para o primeiro horário encontrado
   615→    if (professional.workingHours[0]) {
   616→      return {
   617→        start: professional.workingHours[0].start,
   618→        end: professional.workingHours[0].end,
   619→      };
   620→    }
   621→
   622→    return null;
   623→  };
