   649→
   650→        // Se a API retornou slots, formatar eles do UTC para o timezone do salão
   651→        if (slotsFromAPI.length > 0) {
   652→          const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   653→
   654→          // Converter slots de ISO UTC para HH:mm no timezone do salão
   655→          const formattedSlots = slotsFromAPI.map((slot) => {
   656→            // Se o slot já está em formato HH:mm, manter
   657→            if (slot.match(/^\d{2}:\d{2}$/)) {
